#include <stdio.h>

// Structure to hold value-probability pair
typedef struct {
    double value;
    double prob;
} DistPoint;

double calculate_expected(DistPoint dist[], int n) {
    double sum = 0;
    for (int i = 0; i < n; i++) {
        sum += dist[i].value * dist[i].prob;
    }
    return sum;
}

double calculate_variance(DistPoint dist[], int n, double mean) {
    double sum = 0;
    for (int i = 0; i < n; i++) {
        sum += (dist[i].value - mean) * (dist[i].value - mean) * dist[i].prob;
    }
    return sum;
}

int main() {
    // Example: P(X=1)=0.2, P(X=2)=0.5, P(X=3)=0.3
    DistPoint dist[] = {{1, 0.2}, {2, 0.5}, {3, 0.3}};
    int n = 3;

    double mean = calculate_expected(dist, n);
    double variance = calculate_variance(dist, n, mean);

    printf("Expected Value: %.2f\n", mean);
    printf("Variance: %.2f\n", variance);
    printf("Standard Deviation: %.2f\n", sqrt(variance));

    return 0;
}

import java.util.Random;

public class GeometricDistribution {

    // Generate geometric random variable (count trials until success)
    public static int geometricSample(double p, Random rng) {
        int trials = 1;
        while (rng.nextDouble() > p) {
            trials++;
        }
        return trials;
    }

    // Calculate P(X = k) for Geometric(p)
    public static double geometricPMF(int k, double p) {
        if (k < 1) return 0;
        return Math.pow(1 - p, k - 1) * p;
    }

    // Calculate P(X > k) - probability of needing more than k trials
    public static double geometricTail(int k, double p) {
        return Math.pow(1 - p, k);
    }

    public static void main(String[] args) {
        double p = 0.2;  // success probability

        // Calculate probability of needing more than 3 attempts
        double probMoreThan3 = geometricTail(3, p);
        System.out.println("P(X > 3) = " + probMoreThan3);
        System.out.println("P(X = 3) = " + geometricPMF(3, p));

        // Simulate 10000 trials
        Random rng = new Random(42);
        int[] counts = new int[10];
        for (int i = 0; i < 10000; i++) {
            int result = geometricSample(p, rng);
            if (result <= 9) counts[result - 1]++;
        }

        System.out.println("Simulation results:");
        for (int i = 0; i < 9; i++) {
            System.out.println("X=" + (i+1) + ": " + counts[i] / 10000.0);
        }
    }
}
